EntityListener = {}

function EntityListener:init()
    Listener.registerCallBack(AttackActorNpcEvent, self.onAttackActorNpc)
    LuaTimer:scheduleTimer(function()
        EntityListener.onSelfPlayerMove()
    end, 100)
end

function EntityListener.onSelfPlayerMove()
    if not PlayerManager:getClientPlayer() then
        return
    end
    local pos = PlayerManager:getClientPlayer():getPosition()
    if FuncNpcConfig then
        FuncNpcConfig:onPlayerMove(pos)
    end
end

function EntityListener.onAttackActorNpc(entityId)
    local entity = EntityCache:getEntity(entityId)
    if entity == nil then
        return true
    end
    if type(entity.onPlayerClick) == "function" then
        entity:onPlayerClick()
        return false
    end
    return true
end